import React from 'react';
import { useNavigate } from 'react-router-dom';

/* ─── Inject fonts + keyframes ───────────────────────────── */
const injectGlobal = () => {
  if (document.getElementById('home-global')) return;
  const s = document.createElement('style');
  s.id = 'home-global';
  s.textContent = `
    @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;1,400&family=DM+Sans:wght@300;400;500&display=swap');
    @keyframes fadeUp {
      from { opacity:0; transform:translateY(24px); }
      to   { opacity:1; transform:translateY(0); }
    }
  `;
  document.head.appendChild(s);
};

/* ─── SVG Icons (no external library) ───────────────────── */
const IconStar = () => (
  <svg width="11" height="11" viewBox="0 0 24 24" fill="currentColor">
    <path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z"/>
  </svg>
);
const IconArrow = () => (
  <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/>
  </svg>
);
const IconCheck = ({ color }) => (
  <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round">
    <path d="M22 11.08V12a10 10 0 1 1-5.93-9.14"/>
    <polyline points="22 4 12 14.01 9 11.01"/>
  </svg>
);
const IconZap = ({ color }) => (
  <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round">
    <polygon points="13 2 3 14 12 14 11 22 21 10 12 10 13 2"/>
  </svg>
);
const IconAward = ({ color }) => (
  <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round">
    <circle cx="12" cy="8" r="6"/><path d="M15.477 12.89L17 22l-5-3-5 3 1.523-9.11"/>
  </svg>
);
const IconMicroscope = ({ color }) => (
  <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round">
    <path d="M6 18h8"/><path d="M3 21h18"/><path d="M14 21v-4a2 2 0 0 0-2-2H6a2 2 0 0 0-2 2v4"/>
    <path d="M14 7V3a1 1 0 0 0-1-1H9a1 1 0 0 0-1 1v4"/><path d="M10 7h4"/><path d="M8 7H4"/>
    <circle cx="12" cy="11" r="3"/>
  </svg>
);
const IconGem = ({ color }) => (
  <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round">
    <polygon points="6 3 18 3 22 9 12 22 2 9"/><line x1="2" y1="9" x2="22" y2="9"/>
    <line x1="6" y1="3" x2="12" y2="22"/><line x1="18" y1="3" x2="12" y2="22"/>
  </svg>
);
const IconCalendar = ({ color }) => (
  <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round">
    <rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/>
    <line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/>
    <polyline points="9 16 11 18 15 14"/>
  </svg>
);

/* ─── Design tokens ───────────────────────────────────────── */
const G = '#B89A6A';   // gold
const GL = '#D4B98A';  // gold light
const CH = '#252422';  // charcoal
const IV = '#F7F4EF';  // ivory
const IM = '#EAE5DA';  // ivory-mid
const INK = '#47443E'; // ink
const MU = '#8C897F';  // muted
const WH = '#FFFFFF';  // white
const FD = '"Playfair Display", Georgia, serif';
const FB = '"DM Sans", system-ui, sans-serif';

/* ─── Component ───────────────────────────────────────────── */
export default function Home() {
  const navigate = useNavigate();
  injectGlobal();

  const [hBtn, setHBtn] = React.useState(null);
  const [hCard, setHCard] = React.useState(null);
  const [imgHov, setImgHov] = React.useState(false);

  const features = [
    { Icon: IconAward,     title: 'Expertise reconnue',    text: "Praticiens hautement qualifiés, plus de 20 ans d'expérience." },
    { Icon: IconMicroscope,title: 'Technologies avancées', text: "Équipements dernière génération pour diagnostics précis." },
    { Icon: IconGem,       title: 'Service premium',       text: "Accompagnement personnalisé dans un cadre luxueux et raffiné." },
    { Icon: IconCalendar,  title: 'Horaires flexibles',    text: "Ouvert 6 jours sur 7, avec des plages horaires étendues." },
  ];

  return (
    <div style={{ fontFamily: FB, color: CH, background: IV, overflowX: 'hidden' }}>

      {/* ══ HERO ══════════════════════════════════════════ */}
      <section style={{
        display: 'grid', gridTemplateColumns: '1fr 1fr',
        alignItems: 'center', gap: '4rem',
        padding: '6rem 8vw 4rem', minHeight: '90vh',
      }}>

        {/* Left — content */}
        <div style={{ display: 'flex', flexDirection: 'column', gap: '2rem', animation: 'fadeUp .85s ease both' }}>

          {/* Badge */}
          <span style={{
            display: 'inline-flex', alignItems: 'center', gap: '6px',
            fontSize: '.7rem', fontWeight: 500, letterSpacing: '.14em',
            textTransform: 'uppercase', color: G,
            border: `1px solid ${GL}`, borderRadius: '100px',
            padding: '.38rem 1.1rem', width: 'fit-content',
          }}>
            <IconStar /> Excellence Certifiée
          </span>

          {/* H1 */}
          <h1 style={{
            fontFamily: FD, fontWeight: 400,
            fontSize: 'clamp(2.5rem, 4.5vw, 4.2rem)',
            lineHeight: 1.12, color: CH, letterSpacing: '-.01em', margin: 0,
          }}>
            Votre <em style={{ fontStyle: 'italic', color: G }}>sourire</em>,<br />
            notre passion
          </h1>

          <p style={{ fontSize: '.96rem', fontWeight: 300, color: INK, lineHeight: 1.82, maxWidth: '44ch', margin: 0 }}>
            Des soins dentaires d'exception dans un environnement apaisant.
            Notre équipe vous garantit des résultats parfaits grâce aux
            technologies les plus avancées.
          </p>

          {/* Stats */}
          <div style={{
            display: 'flex', alignItems: 'center',
            padding: '1.5rem 0',
            borderTop: `1px solid ${IM}`, borderBottom: `1px solid ${IM}`,
          }}>
            {[
              { n: '20+',   l: "Années d'expérience" },
              { n: '15 k+', l: 'Patients satisfaits' },
              { n: '98 %',  l: 'Taux de satisfaction' },
            ].map(({ n, l }, i) => (
              <React.Fragment key={l}>
                {i > 0 && <div style={{ width: '1px', height: '2.4rem', background: IM, flexShrink: 0 }} />}
                <div style={{ display: 'flex', flexDirection: 'column', gap: '.25rem', padding: i === 0 ? '0 1.8rem 0 0' : '0 1.8rem' }}>
                  <span style={{ fontFamily: FD, fontWeight: 400, fontSize: '1.9rem', color: CH, lineHeight: 1 }}>{n}</span>
                  <span style={{ fontSize: '.73rem', color: MU, letterSpacing: '.03em' }}>{l}</span>
                </div>
              </React.Fragment>
            ))}
          </div>

          {/* Buttons */}
          <div style={{ display: 'flex', gap: '.9rem', flexWrap: 'wrap' }}>
            <button
              onMouseEnter={() => setHBtn('p')} onMouseLeave={() => setHBtn(null)}
              onClick={() => navigate('/services')}
              style={{
                display: 'inline-flex', alignItems: 'center', gap: '8px',
                fontFamily: FB, fontSize: '.85rem', fontWeight: 500, letterSpacing: '.03em',
                background: hBtn === 'p' ? G : CH, color: IV,
                border: 'none', borderRadius: '100px', padding: '.85rem 2rem', cursor: 'pointer',
                transform: hBtn === 'p' ? 'translateY(-2px)' : 'none',
                boxShadow: hBtn === 'p' ? '0 8px 28px rgba(184,154,106,.38)' : 'none',
                transition: 'all .22s ease',
              }}
            >
              Nos services <IconArrow />
            </button>
            <button
              onMouseEnter={() => setHBtn('o')} onMouseLeave={() => setHBtn(null)}
              onClick={() => navigate('/about')}
              style={{
                display: 'inline-flex', alignItems: 'center', gap: '8px',
                fontFamily: FB, fontSize: '.85rem', fontWeight: 500, letterSpacing: '.03em',
                background: hBtn === 'o' ? CH : 'transparent',
                color: hBtn === 'o' ? IV : CH,
                border: `1px solid ${CH}`, borderRadius: '100px',
                padding: '.85rem 2rem', cursor: 'pointer',
                transform: hBtn === 'o' ? 'translateY(-2px)' : 'none',
                transition: 'all .22s ease',
              }}
            >
              À propos
            </button>
          </div>
        </div>

        {/* Right — image */}
        <div style={{ position: 'relative', animation: 'fadeUp .85s .2s ease both', opacity: 0 }}>
          <div
            onMouseEnter={() => setImgHov(true)} onMouseLeave={() => setImgHov(false)}
            style={{
              borderRadius: '24px', overflow: 'hidden', aspectRatio: '4/5',
              boxShadow: `0 0 0 1px ${IV}, 0 0 0 2px ${GL}, 0 30px 80px rgba(37,36,34,.14)`,
            }}
          >
            <img
              src="https://images.unsplash.com/photo-1606811841689-23dfddce3e95?w=900&h=700&fit=crop&q=90"
              alt="Cabinet dentaire moderne"
              style={{
                width: '100%', height: '100%', objectFit: 'cover', display: 'block',
                transform: imgHov ? 'scale(1.05)' : 'scale(1)',
                transition: 'transform 7s ease',
              }}
            />
          </div>

          {/* Pill 1 */}
          <div style={{
            position: 'absolute', bottom: '9%', left: '-1.5rem',
            display: 'flex', alignItems: 'center', gap: '.65rem',
            background: WH, border: `1px solid ${IM}`, borderRadius: '14px',
            padding: '.75rem 1.1rem', boxShadow: '0 12px 40px rgba(37,36,34,.1)',
            animation: 'fadeUp .8s .5s ease both', opacity: 0,
          }}>
            <IconCheck color={G} />
            <div>
              <p style={{ fontSize: '.82rem', fontWeight: 500, color: CH, margin: 0, whiteSpace: 'nowrap' }}>Équipe certifiée</p>
              <p style={{ fontSize: '.72rem', color: MU, margin: '.1rem 0 0' }}>Dentistes diplômés</p>
            </div>
          </div>

          {/* Pill 2 */}
          <div style={{
            position: 'absolute', top: '10%', right: '-1.5rem',
            display: 'flex', alignItems: 'center', gap: '.65rem',
            background: WH, border: `1px solid ${IM}`, borderRadius: '14px',
            padding: '.75rem 1.1rem', boxShadow: '0 12px 40px rgba(37,36,34,.1)',
            animation: 'fadeUp .8s .7s ease both', opacity: 0,
          }}>
            <IconZap color={G} />
            <div>
              <p style={{ fontSize: '.82rem', fontWeight: 500, color: CH, margin: 0, whiteSpace: 'nowrap' }}>Technologies avancées</p>
              <p style={{ fontSize: '.72rem', color: MU, margin: '.1rem 0 0' }}>Équipements de pointe</p>
            </div>
          </div>
        </div>
      </section>

      {/* ══ FEATURES ══════════════════════════════════════ */}
      <section style={{ padding: '7rem 8vw', background: WH }}>
        <header style={{ textAlign: 'center', maxWidth: '560px', margin: '0 auto 4rem' }}>
          <span style={{
            display: 'inline-block', fontSize: '.7rem', fontWeight: 500,
            letterSpacing: '.14em', textTransform: 'uppercase', color: G, marginBottom: '.9rem',
          }}>
            Pourquoi nous choisir
          </span>
          <h2 style={{
            fontFamily: FD, fontWeight: 400,
            fontSize: 'clamp(1.9rem, 3vw, 2.7rem)',
            color: CH, lineHeight: 1.22, letterSpacing: '-.01em', marginBottom: '.85rem',
          }}>
            L'excellence à votre service
          </h2>
          <p style={{ fontSize: '.94rem', fontWeight: 300, color: INK, lineHeight: 1.78, margin: 0 }}>
            Une approche complète alliant expertise médicale, technologies
            de pointe et accompagnement personnalisé.
          </p>
        </header>

        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '1.4rem' }}>
          {features.map(({ Icon, title, text }, i) => (
            <div
              key={title}
              onMouseEnter={() => setHCard(i)} onMouseLeave={() => setHCard(null)}
              style={{
                background: IV,
                border: `1px solid ${hCard === i ? GL : IM}`,
                borderRadius: '16px', padding: '2rem 1.6rem',
                transform: hCard === i ? 'translateY(-6px)' : 'none',
                boxShadow: hCard === i ? '0 20px 50px rgba(37,36,34,.09)' : 'none',
                transition: 'all .28s ease', cursor: 'default',
                animation: `fadeUp .7s ${0.1 + i * 0.1}s ease both`, opacity: 0,
              }}
            >
              <div style={{
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                width: '48px', height: '48px',
                background: 'rgba(184,154,106,.12)', borderRadius: '12px',
                marginBottom: '1.25rem', color: G,
              }}>
                <Icon color={G} />
              </div>
              <h3 style={{ fontFamily: FD, fontWeight: 400, fontSize: '1.2rem', color: CH, marginBottom: '.55rem' }}>
                {title}
              </h3>
              <p style={{ fontSize: '.87rem', fontWeight: 300, color: INK, lineHeight: 1.72, margin: 0 }}>
                {text}
              </p>
            </div>
          ))}
        </div>
      </section>

    </div>
  );
}
